var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르, 상황 보고해 봐.","JPN":"イェゴール、状況を報告して。","ENG":"Yegor, what’s the situation?","TWN":"伊高爾，回報戰況！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"찰과상을 입은 몇 명을 제외하고는 전원 무사합니다. 수송기의 추진기가 피격당하긴 했지만요.","JPN":"何人かかすり傷を負った程度で、全員無事です。輸送機の推進機がダメージを受けましたが。","ENG":"Except for a few burns, everyone is fine. Although the transporter’s thrusters were shot.","TWN":"有部分人員受到擦傷，其餘皆無礙，不過運輸機的推進器有受到攻擊。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……그래. 계속해.","JPN":"……そう。続けて。","ENG":"...I see. Continue.","TWN":"……好，繼續說。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"네. 타이런트 타입은 요격 성공. 셰나는 종적을 감췄습니다.","JPN":"はい。タイラントタイプの迎撃に成功。シェナは姿を消しました。","ENG":"The Tyrant Type was successfully intercepted. All signs of Shena have disappeared.","TWN":"是，暴君類型攔擊成功，世娜不知去向。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"지근거리에서 타라스크의 포격에 당했으니 멀리 가진 못했을 겁니다. 추격할까요?","JPN":"至近距離からタラスクの砲撃にやられたので、遠くは行っていないはずです。追撃しましょうか？","ENG":"She can’t have made it far after being hit by the Tarrasque. Shall we pursue?","TWN":"她是在近距離受到特拉斯克的砲擊，應該無法跑遠，要追嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모네카, 아직 셰나의 침식파가 감지되려나?","JPN":"モネカ、シェナの侵食波はまだ感知できる？","ENG":"Moneka, can you still sense Shena’s Corruption ray signal?","TWN":"莫奈卡，還有感應到世娜的侵蝕波嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"네. 현재 침식파 반응은 북서쪽 방향으로 이동 중.","JPN":"はい。現在、侵食波反応は北西へと移動中。","ENG":"Yes. The Corruption ray’s signal is currently moving northwest.","TWN":"有，現在侵蝕波反應正往西北方移動中。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"아슬아슬하게 탐지 반경에 걸쳐 있어요. 지금 출발하면 금방 따라잡을 거예요.","JPN":"ギリギリ探知半径内です。今出発したらすぐ追いつけますよ。","ENG":"We’re narrowly detecting the signal. If we move to intercept now we will catch up quickly.","TWN":"正經過監測半徑，現在出發的話，應該很快就能追上。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 애들 불러들여. 타나베린으로 철수하자.","JPN":"よし。子どもたちを呼び戻して。タナベリンに撤退するわ。","ENG":"Okay. Recall all of them. Let’s withdraw to Tanaberin.","TWN":"好，把孩子們叫來，撤退到達那貝林！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"철수한다고 하셨습니까?","JPN":"撤退するとおっしゃいましたか？","ENG":"Did you say withdraw?","TWN":"你是說撤退嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"왜 그렇게 놀라고 그러니?","JPN":"なんで驚くの？","ENG":"Why are you so surprised?","TWN":"有什麼好驚訝的？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"상대가 다른 엘리시움 단원도 아니고 셰나이지 않습니까.","JPN":"相手は他のエリシウム団員でもなく、シェナではないですか。","ENG":"It’s not just any other Elysium member, it’s Shena.","TWN":"對方不是別人，是世娜欸？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님에게는 원수 같은 그림자일 텐데……. 격퇴할 수 있는 기회를 포기하신다니 이해하기 어렵습니다. ","JPN":"副戦隊長にとっては仇のようなシャドウのはず……撃退できるチャンスをあきらめるなんて、理解できません。","ENG":"It’s an enemy Shadow no better than the stone in your shoe……. It’s difficult to understand why you’re passing up such an opportunity.","TWN":"她應該是副戰隊長的死對頭吧……現在有機會可以打倒她，為什麼要放棄？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"잘 아네. 죽여 버리고는 싶어.","JPN":"よくわかってるわね。殺したくはあるの。","ENG":"I am well aware. I want nothing more than to kill her, too.","TWN":"你倒是很清楚嘛，我是想殺死她沒錯。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"비유하기도 역겹지만, 그것들은 자식이 원하는 대로 태어나지 않았다고 쓰레기처럼 버려 버린 부모나 마찬가지니까.","JPN":"例えるだけで吐き気がするけど、あれは理想的な子どもが生まれなかったからってゴミのように捨てる親も同然だから。","ENG":"It's a horrible comparison to make, but they're like parents who cast out their children for not being born the way they want them to be.","TWN":"這個比喻可能會讓人有點不舒服，但她們就跟那些因為孩子不是照自己的期待出生，就將孩子像垃圾一般丟棄的父母一樣！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"……. ","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 개인적인 감정 때문에 너희들을 위험에 빠뜨릴 생각은 없어.","JPN":"でも私情であなたたちを危険にさらすつもりはないの。","ENG":"Even so, I won’t put you guys at risk because of personal feelings.","TWN":"但我不想因為私人恩怨，而使你們陷入危險當中。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그게 그 개자식이 의도한 거라면 더더욱.","JPN":"それがあのクソ野郎が狙ってることならなおさらね。","ENG":"And all the more, if that is her intention.","TWN":"我不想正中她下懷！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};